import React, { useState } from "react";
import axios from "axios";

const Register = () => {
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    role: "customer"
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleRegister = async (e) => {
    e.preventDefault();

    try {
      await axios.post(
        "http://localhost:5000/api/auth/register",
        form
      );

      alert("Registered Successfully");
      window.location.href = "/login";

    } catch (err) {
      alert("Register failed");
    }
  };

  return (
    <div style={styles.container}>

      <h2>Register</h2>

      <form onSubmit={handleRegister} style={styles.form}>

        <input name="name" placeholder="Name" onChange={handleChange} style={styles.input} />

        <input name="email" placeholder="Email" onChange={handleChange} style={styles.input} />

        <input name="password" type="password" placeholder="Password" onChange={handleChange} style={styles.input} />

        <select name="role" onChange={handleChange} style={styles.input}>
          <option value="customer">Customer</option>
          <option value="labour">Labour</option>
        </select>

        <button style={styles.btn}>Register</button>

      </form>

    </div>
  );
};

export default Register;

const styles = {
  container: {
    height: "100vh",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Segoe UI"
  },

  form: {
    display: "flex",
    flexDirection: "column",
    width: "250px"
  },

  input: {
    padding: "10px",
    margin: "5px 0",
    border: "1px solid #ccc",
    borderRadius: "6px"
  },

  btn: {
    padding: "10px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "6px",
    marginTop: "10px"
  }
};
